    my ($filename) = @_;
    my $pdf = PDF::API2->open($filename);
    my $pages = $pdf->pages;

    my @texts;
    for (my $p = 1; $p <= $pages; $p++) {
        my $page = $pdf->page($p);
        my $text = $page->text;
        push @texts, $text;
    }
    return join("\n", @texts);
}

